#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include <type_traits>
#include <functional>

namespace internal {

// A single pass of a block-based parallel radix sort.
// It stably sorts `In` into `Out` based on the bits from `bits_start` to `bits_start + bits_per_pass`.
template <class T, class K, class GetKey>
void radix_pass(parlay::slice<T*, T*> In, parlay::slice<T*, T*> Out,
                size_t bits_start, size_t bits_per_pass,
                const GetKey& get_key_unsigned) {
    size_t n = In.size();
    size_t num_buckets = 1 << bits_per_pass;
    K mask = num_buckets - 1;

    // The block size is chosen to balance parallelism and per-block overhead.
    // A larger block size reduces overhead but limits parallelism.
    size_t block_size = parlay::internal::get_default_block_size();
    if (block_size < 2048) block_size = 2048;
    size_t num_blocks = (n + block_size - 1) / block_size;

    // 1. Count in parallel blocks
    // block_counts[i][j] stores the count of elements with digit j in block i.
    auto block_counts = parlay::sequence<parlay::sequence<size_t>>::uninitialized(num_blocks);
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        block_counts[i] = parlay::sequence<size_t>(num_buckets, (size_t)0);
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        for (size_t j = start; j < end; j++) {
            K key = get_key_unsigned(In[j]);
            size_t bucket = (key >> bits_start) & mask;
            block_counts[i][bucket]++;
        }
    });

    // 2. Calculate global bucket offsets
    // bucket_offsets[j] will store the starting position in the output array
    // for all elements with digit j.
    auto bucket_offsets = parlay::sequence<size_t>(num_buckets);
    parlay::parallel_for(0, num_buckets, [&](size_t j) {
        size_t total = 0;
        for (size_t i = 0; i < num_blocks; i++) {
            total += block_counts[i][j];
        }
        bucket_offsets[j] = total;
    });

    // Perform an exclusive scan on the total counts to get the final offsets.
    parlay::scan_inplace(bucket_offsets, parlay::plus<size_t>());

    // 3. Update block_counts to be the scatter offsets for each block.
    // After this, block_counts[i][j] will store the starting position in the
    // output array for elements with digit j from block i.
    parlay::parallel_for(0, num_buckets, [&](size_t j) {
        size_t current_offset = bucket_offsets[j];
        for (size_t i = 0; i < num_blocks; i++) {
            size_t count = block_counts[i][j];
            block_counts[i][j] = current_offset;
            current_offset += count;
        }
    });

    // 4. Scatter data to the output array in parallel.
    // Each thread processes its block and places elements into their correct
    // final positions in `Out`. There are no write conflicts.
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        for (size_t j = start; j < end; j++) {
            K key = get_key_unsigned(In[j]);
            size_t bucket = (key >> bits_start) & mask;
            size_t dest = block_counts[i][bucket]++;
            Out[dest] = std::move(In[j]);
        }
    });
}

} // namespace internal


/**
 * @brief Parallel integer sort (LSD Radix Sort).
 *
 * Sorts a sequence of elements based on an integer key.
 *
 * @tparam T The type of the elements in the sequence.
 * @tparam GetKey A function object type that extracts an integer key from an element of type T.
 *                Defaults to identity for sorting sequences of integers.
 * @param In The input slice to be sorted. The result will be stored in this slice.
 * @param bits The number of bits in the key to sort on (e.g., 32 for int, 64 for long).
 * @param getKey An instance of the GetKey function object.
 * @return The input slice, now containing the sorted elements.
 */
template <class T, class GetKey = std::identity>
auto int_sort(parlay::slice<T*,T*> In, size_t bits, GetKey getKey = {}) {
    size_t n = In.size();
    if (n == 0) return In;

    // Use a sequential sort for small inputs where parallel overhead is too high.
    constexpr size_t sequential_threshold = 2048;
    if (n < sequential_threshold) {
        std::sort(In.begin(), In.end(), [&](const T& a, const T& b) {
            return getKey(a) < getKey(b);
        });
        return In;
    }

    // Determine the integer key type.
    using K = std::invoke_result_t<GetKey, T>;
    static_assert(std::is_integral_v<K>, "GetKey must return an integral type.");

    // Radix sort works on unsigned integers. For signed integers, we must
    // transform them to preserve order (e.g., by flipping the sign bit).
    auto get_key_unsigned = [&](const T& val) -> std::make_unsigned_t<K> {
        K key = getKey(val);
        if constexpr (std::is_signed_v<K>) {
            // This maps [min, -1] to [0, max] and [0, max] to [max+1, ...].
            // The cast to unsigned is well-defined and does what we want.
            return static_cast<std::make_unsigned_t<K>>(key) ^ (std::make_unsigned_t<K>(1) << (sizeof(K) * 8 - 1));
        } else {
            return key;
        }
    };

    constexpr size_t bits_per_pass = 8;
    size_t num_passes = (bits + bits_per_pass - 1) / bits_per_pass;

    // Use a temporary buffer for ping-ponging data between passes.
    auto Tmp = parlay::sequence<T>::uninitialized(n);
    parlay::slice<T*, T*> current_in = In;
    parlay::slice<T*, T*> current_out = Tmp.slice();

    for (size_t i = 0; i < num_passes; ++i) {
        internal::radix_pass<T, std::make_unsigned_t<K>>(
            current_in, current_out, i * bits_per_pass, bits_per_pass, get_key_unsigned);
        std::swap(current_in, current_out);
    }

    // If the number of passes is odd, the final result is in the temporary buffer.
    // We need to copy it back to the original input slice.
    if (num_passes % 2 == 1) {
        parlay::copy(Tmp, In);
    }

    return In;
}
